CREATE TABLE strategies (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  name VARCHAR(255) NOT NULL UNIQUE,\n  description TEXT,\n  enabled BOOLEAN DEFAULT true,\n  created_at TIMESTAMP DEFAULT NOW()\n);\n\nCREATE TABLE signals (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  strategy_id UUID NOT NULL REFERENCES strategies(id),\n  symbol VARCHAR(20) NOT NULL,\n  direction VARCHAR(10) NOT NULL,\n  confidence FLOAT NOT NULL,\n  price FLOAT NOT NULL,\n  timestamp TIMESTAMP DEFAULT NOW()\n);\n\nCREATE TABLE allocations (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  strategy_id UUID NOT NULL REFERENCES strategies(id),\n  weight FLOAT NOT NULL,\n  timestamp TIMESTAMP DEFAULT NOW()\n);\n\nCREATE TABLE trades (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  strategy_id UUID NOT NULL REFERENCES strategies(id),\n  symbol VARCHAR(20) NOT NULL,\n  side VARCHAR(10) NOT NULL,\n  size FLOAT NOT NULL,\n  entry_price FLOAT NOT NULL,\n  exit_price FLOAT,\n  stop_loss FLOAT,\n  take_profit FLOAT,\n  pnl FLOAT,\n  status VARCHAR(20) DEFAULT 'OPEN',\n  created_at TIMESTAMP DEFAULT NOW(),\n  updated_at TIMESTAMP DEFAULT NOW()\n);\n\nCREATE TABLE performance (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  strategy_id UUID NOT NULL REFERENCES strategies(id),\n  sharpe_ratio FLOAT,\n  win_rate FLOAT,\n  consistency FLOAT,\n  max_drawdown FLOAT,\n  total_pnl FLOAT,\n  created_at TIMESTAMP DEFAULT NOW()\n);\n\nCREATE TABLE audit_logs (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  event VARCHAR(255) NOT NULL,\n  severity VARCHAR(20),\n  details JSONB,\n  timestamp TIMESTAMP DEFAULT NOW()\n);\n\nCREATE INDEX idx_strategies_enabled ON strategies(enabled);\nCREATE INDEX idx_signals_strategy ON signals(strategy_id);\nCREATE INDEX idx_allocations_strategy ON allocations(strategy_id);\nCREATE INDEX idx_trades_strategy ON trades(strategy_id);\nCREATE INDEX idx_trades_status ON trades(status);\nCREATE INDEX idx_performance_strategy ON performance(strategy_id);